const msg = $input.first().json;
const text = (msg.message && msg.message.text ? msg.message.text : "").trim();
const chatId = msg.message && msg.message.chat ? msg.message.chat.id : null;
const parts = text.split(/\s+/);
const arg = (parts[1] || "").toLowerCase();

let action, time = null, reply_invalid = null;
if (!arg) {
  action = "status";
} else if (arg === "off" || arg === "apagar") {
  action = "off";
} else if (/^([01]\d|2[0-3]):([0-5]\d)$/.test(arg)) {
  action = "set"; time = arg;
} else {
  action = "invalid";
  reply_invalid = "Formato invalido. Usa: /despertador HH:MM (ej 07:30) o /despertador off";
}

let sql;
if (action === "set") {
  sql = `UPDATE alarm_config SET alarm_time='${time}', enabled=true, updated_at=now() WHERE id=1 RETURNING alarm_time, enabled;`;
} else if (action === "off") {
  sql = `UPDATE alarm_config SET enabled=false, updated_at=now() WHERE id=1 RETURNING alarm_time, enabled;`;
} else {
  sql = `SELECT alarm_time, enabled FROM alarm_config WHERE id=1;`;
}
return [{ json: { action, time, chatId, sql, reply_invalid } }];

const p = $('Parsear comando').first().json;
const row = $input.first().json || {};
const chatId = p.chatId;
let text;
if (p.action === 'invalid') {
  text = p.reply_invalid;
} else if (p.action === 'set') {
  text = `Despertador programado a las ${row.alarm_time} hs, todos los dias.`;
} else if (p.action === 'off') {
  text = `Despertador anulado. No va a sonar hasta que lo vuelvas a programar.`;
} else {
  if (row.enabled && row.alarm_time) {
    text = `Despertador activo a las ${row.alarm_time} hs, todos los dias.\nCambiar: /despertador HH:MM\nAnular: /despertador off`;
  } else {
    text = `Despertador apagado.\nProgramar: /despertador HH:MM`;
  }
}
return [{ json: { chatId, text } }];
